#include<bits/stdc++.h>
using namespace std;
struct query
{
    long long l,r,y,val;
    bool operator<(const query&b)const
    {
        if(y==b.y)
        {
            return val<b.val;
        }
        return y<b.y;
    }
}a[2000010];
struct segment_tree
{
    struct node
    {
        long long l,r,lson,rson;
        long long max1;
        long long tag;
    }a[6000010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushdown(long long x)
    {
        if(a[x].tag)
        {
            long long mid=(a[x].l+a[x].r)>>1;
            if(!a[x].lson)
            {
                a[x].lson=++cnt;
                a[a[x].lson].l=a[x].l;
                a[a[x].lson].r=mid;
                a[a[x].lson].max1=0;
                a[a[x].lson].tag=0;
                a[cnt].lson=a[cnt].rson=0;
            }
            if(!a[x].rson)
            {
                a[x].rson=++cnt;
                a[a[x].rson].l=mid+1;
                a[a[x].rson].r=a[x].r;
                a[a[x].rson].max1=0;
                a[a[x].rson].tag=0;
                a[cnt].lson=a[cnt].rson=0;
            }
            long long tg=a[x].tag;
            long long ls=a[x].lson,rs=a[x].rson;
            a[ls].max1+=tg;
            a[ls].tag+=tg;
            a[rs].max1+=tg;
            a[rs].tag+=tg;
            a[x].tag=0;
        }
    }
    void pushup(long long x)
    {
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
    }
    void add(long long &x,long long l,long long r,long long v,long long newl,long long newr)
    {
        if(x==0)
        {
            x=++cnt;
            a[x].l=newl;
            a[x].r=newr;
            a[x].tag=0;
            a[x].max1=0;
            a[x].lson=a[x].rson=0;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].tag+=v;
            a[x].max1+=v;
            return;
        }
        pushdown(x);
        long long mid=(a[x].l+a[x].r)>>1;
        if(l<=mid)
        {
            add(a[x].lson,l,r,v,newl,mid);
        }
        if(r>mid)
        {
            add(a[x].rson,l,r,v,mid+1,newr);
        }
        pushup(x);
    }
}t;
long long root,k=0,ans[2000010];
void add(long long l,long long r,long long y,long long val)
{
    a[++::k].l=l;
    a[::k].r=r;
    a[::k].y=y;
    a[::k].val=val;
}
void add_matrix(long long ax,long long ay,long long bx,long long by,long long val)
{
    add(ax,bx,ay,val);
    add(ax,bx,by+1,-val);
}
int main()
{
    long long T;
    scanf("%lld",&T);
    while(T--)
    {
        k=0;
        root=0;
        t.cnt=0;
        long long n,h,w;
        scanf("%lld%lld%lld",&n,&w,&h);
        for(long long i=1;i<=n;i++)
        {
            long long x,y,l;
            scanf("%lld%lld%lld",&x,&y,&l);
            add_matrix(x,y,x+w-1,y+h-1,l);
        }
        sort(a+1,a+1+k);
        long long ans=0;
        for(long long i=1;i<=k;i++)
        {
            t.add(root,a[i].l,a[i].r,a[i].val,1,INT_MAX);
            // printf("add(%lld,%lld,%lld) a[i].y=%lld\n",a[i].l,a[i].r,a[i].val,a[i].y);
            ans=max(ans,t.a[root].max1);
        }
        printf("%lld\n",ans);
    }
    return 0;
}
